// Config holds server configuration
type Config struct {
	Port       string
	TLSCert    string
	TLSKey     string
	CACert     string
	AuthToken  string
	MaxMsgSize int
}

func loadConfig() *Config {
	return &Config{
		Port:       getEnv("GRPC_PORT", "50051"),
		TLSCert:    getEnv("TLS_CERT_PATH", "certs/server.crt"),
		TLSKey:     getEnv("TLS_KEY_PATH", "certs/server.key"),
		CACert:     getEnv("CA_CERT_PATH", "certs/ca.crt"),
		AuthToken:  getEnv("AUTH_TOKEN", ""),
		MaxMsgSize: 4 * 1024 * 1024, // 4MB
	}
}

func getEnv(key, fallback string) string {
	if value, ok := os.LookupEnv(key); ok {
		return value
	}
	return fallback
}

// loadTLSCredentials creates mutual TLS credentials
func loadTLSCredentials(cfg *Config) (credentials.TransportCredentials, error) {
	// Load CA certificate for client verification (mTLS)
	caCert, err := os.ReadFile(cfg.CACert)
	if err != nil {
		return nil, fmt.Errorf("failed to read CA cert: %w", err)
	}

	certPool := x509.NewCertPool()
	if !certPool.AppendCertsFromPEM(caCert) {
		return nil, fmt.Errorf("failed to add CA cert to pool")
	}

	// Load server certificate and key
	serverCert, err := tls.LoadX509KeyPair(cfg.TLSCert, cfg.TLSKey)
	if err != nil {
		return nil, fmt.Errorf("failed to load server cert/key: %w", err)
	}

	tlsConfig := &tls.Config{
		Certificates: []tls.Certificate{serverCert},
		ClientAuth:   tls.RequireAndVerifyClientCert,
		ClientCAs:    certPool,
		MinVersion:   tls.VersionTLS13,
		CipherSuites: []uint16{
			tls.TLS_AES_256_GCM_SHA384,
			tls.TLS_AES_128_GCM_SHA256,
			tls.TLS_CHACHA20_POLY1305_SHA256,
		},
	}

	return credentials.NewTLS(tlsConfig), nil
}

// authUnaryInterceptor validates authentication tokens on unary RPCs
func authUnaryInterceptor(expectedToken string) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Allow reflection calls but still require TLS (mTLS handles auth at transport level)
		// Additional token-based auth for defense in depth
		if expectedToken != "" {
			if err := validateToken(ctx, expectedToken); err != nil {
				return nil, err
			}
		}

		// Log the call for audit
		logRequest(ctx, info.FullMethod)

		return handler(ctx, req)
	}
}

// authStreamInterceptor validates authentication tokens on streaming RPCs
func authStreamInterceptor(expectedToken string) grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		if expectedToken != "" {
			if err := validateToken(ss.Context(), expectedToken); err != nil {
				return err
			}
		}

		logRequest(ss.Context(), info.FullMethod)

		return handler(srv, ss)
	}
}

func validateToken(ctx context.Context, expectedToken string) error {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return status.Error(codes.Unauthenticated, "missing metadata")
	}

	tokens := md.Get("authorization")
	if len(tokens) == 0 {
		return status.Error(codes.Unauthenticated, "missing authorization token")
	}

	token := tokens[0]
	expectedValue := "Bearer " + expectedToken
	if token != expectedValue {
		return status.Error(codes.Unauthenticated, "invalid authorization token")
	}

	return nil
}

func logRequest(ctx context.Context, method string) {
	p, ok := peer.FromContext(ctx)
	peerAddr := "unknown"
	if ok {
		peerAddr = p.Addr.String()
	}
	log.Printf("gRPC call: method=%s peer=%s time=%s", method, peerAddr, time.Now().UTC().Format(time.RFC3339))
}

